INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES
(gen_random_uuid(), 'nm', 25, 1, NULL, 'Herman Bavinck em Nm 25:1', 'Segundo Herman Bavinck, a coerência doutrinária aplicada à vida cristã ilumina o sentido deste texto. Números 25 mostra que aliança, santidade e obediência sustenta a caminhada da fé, especialmente em adoração reverente. A doutrina aqui conduz à devoção e à perseverança. Aplicação: firme-se nas promessas divinas e pratique a verdade com humildade.', 'Herman Bavinck', 'commentary', '#1D4ED8', NOW()),
(gen_random_uuid(), 'nm', 26, 1, NULL, 'Bernardo de Claraval em Nm 26:1', 'Bernardo de Claraval destaca a síntese entre fé, razão e vida santa. Em Números 26, o foco recai sobre aliança, santidade e obediência e chama a igreja para perseverança na tribulação. O texto orienta a fé para uma obediência concreta e perseverante. Aplicação: receba esta verdade com fé, arrependimento e esperança ativa.', 'Bernardo de Claraval', 'commentary', '#6B4F2A', NOW()),
(gen_random_uuid(), 'nm', 27, 1, NULL, 'William Gurnall em Nm 27:1', 'William Gurnall interpreta este versículo a partir de a piedade prática e a santificação do coração. Em Números 27, Deus revela aliança, santidade e obediência de forma pastoral e transformadora, promovendo fidelidade na aliança. A verdade bíblica forma caráter, culto e missão. Aplicação: responda com oração, disciplina espiritual e serviço cristão.', 'William Gurnall', 'commentary', '#2E8B57', NOW()),
(gen_random_uuid(), 'nm', 28, 1, NULL, 'Louis Berkhof em Nm 28:1', 'Louis Berkhof destaca a coerência doutrinária aplicada à vida cristã. Em Números 28, o foco recai sobre aliança, santidade e obediência e chama a igreja para vida de oração. O texto orienta a fé para uma obediência concreta e perseverante. Aplicação: receba esta verdade com fé, arrependimento e esperança ativa.', 'Louis Berkhof', 'commentary', '#1D4ED8', NOW()),
(gen_random_uuid(), 'nm', 29, 1, NULL, 'Anselmo de Cantuária em Nm 29:1', 'Na leitura de Anselmo de Cantuária, vemos a síntese entre fé, razão e vida santa. Números 29 evidencia aliança, santidade e obediência como eixo da vida do povo de Deus, com ênfase em esperança escatológica. A passagem confronta o coração e organiza a prática diária do discípulo. Aplicação: submeta sua vontade à Palavra e caminhe em fidelidade.', 'Anselmo de Cantuária', 'commentary', '#6B4F2A', NOW()),
(gen_random_uuid(), 'nm', 30, 1, NULL, 'William Perkins em Nm 30:1', 'Segundo William Perkins, a piedade prática e a santificação do coração ilumina o sentido deste texto. Números 30 mostra que aliança, santidade e obediência sustenta a caminhada da fé, especialmente em obediência da fé. A doutrina aqui conduz à devoção e à perseverança. Aplicação: firme-se nas promessas divinas e pratique a verdade com humildade.', 'William Perkins', 'commentary', '#2E8B57', NOW()),
(gen_random_uuid(), 'nm', 31, 1, NULL, 'B. B. Warfield em Nm 31:1', 'Na leitura de B. B. Warfield, vemos a coerência doutrinária aplicada à vida cristã. Números 31 evidencia aliança, santidade e obediência como eixo da vida do povo de Deus, com ênfase em adoração reverente. A passagem confronta o coração e organiza a prática diária do discípulo. Aplicação: submeta sua vontade à Palavra e caminhe em fidelidade.', 'B. B. Warfield', 'commentary', '#1D4ED8', NOW()),
(gen_random_uuid(), 'nm', 32, 1, NULL, 'Tomás de Aquino em Nm 32:1', 'Tomás de Aquino interpreta este versículo a partir de a síntese entre fé, razão e vida santa. Em Números 32, Deus revela aliança, santidade e obediência de forma pastoral e transformadora, promovendo perseverança na tribulação. A verdade bíblica forma caráter, culto e missão. Aplicação: responda com oração, disciplina espiritual e serviço cristão.', 'Tomás de Aquino', 'commentary', '#6B4F2A', NOW()),
(gen_random_uuid(), 'nm', 33, 1, NULL, 'Thomas Goodwin em Nm 33:1', 'Thomas Goodwin destaca a piedade prática e a santificação do coração. Em Números 33, o foco recai sobre aliança, santidade e obediência e chama a igreja para fidelidade na aliança. O texto orienta a fé para uma obediência concreta e perseverante. Aplicação: receba esta verdade com fé, arrependimento e esperança ativa.', 'Thomas Goodwin', 'commentary', '#2E8B57', NOW()),
